diff --git a/llvm/lib/Transforms/Vectorize/VPlanRecipes.cpp b/llvm/lib/Transforms/Vectorize/VPlanRecipes.cpp
index 11b4677ec102..a60897ef64d2 100644
--- a/llvm/lib/Transforms/Vectorize/VPlanRecipes.cpp
+++ b/llvm/lib/Transforms/Vectorize/VPlanRecipes.cpp
@@ -2833,9 +2833,52 @@ static void scalarizeInstruction(const Instruction *Instr,
   // Does this instruction return a value ?
   bool IsVoidRetTy = Instr->getType()->isVoidTy();

-  Instruction *Cloned = Instr->clone();
+  // Compute inferred type first; for selects operands may have been
+  // simplified (extends removed) resulting in a narrower inferred type.
+  Type *InferredTy = nullptr;
+  if (!IsVoidRetTy)
+    InferredTy = State.TypeAnalysis.inferScalarType(RepRecipe);
+
+  Instruction *Cloned = nullptr;
+  bool RebuildSelect = Instr->getOpcode() == Instruction::Select && InferredTy &&
+                       InferredTy != Instr->getType();
+  if (RebuildSelect) {
+    // Build a fresh select with the inferred (narrowed) result type instead of
+    // cloning the original wide select. Gather lane-specific operands first.
+    SmallVector<Value *, 3> Ops;
+    for (const auto &E : enumerate(RepRecipe->operands())) {
+      auto InputLane = Lane;
+      VPValue *Operand = E.value();
+      if (vputils::isSingleScalar(Operand))
+        InputLane = VPLane::getFirstLane();
+      Value *MappedOp = State.get(Operand, InputLane);
+      // For value operands (indices 1 and 2), ensure they match InferredTy.
+      if (E.index() > 0 && MappedOp->getType() != InferredTy &&
+          InferredTy->isIntegerTy() && MappedOp->getType()->isIntegerTy()) {
+        unsigned FromBW = MappedOp->getType()->getIntegerBitWidth();
+        unsigned ToBW = InferredTy->getIntegerBitWidth();
+        if (FromBW < ToBW)
+          MappedOp = State.Builder.CreateZExt(MappedOp, InferredTy,
+                                              MappedOp->getName() + ".zext");
+        else if (FromBW > ToBW)
+          MappedOp = State.Builder.CreateTrunc(MappedOp, InferredTy,
+                                               MappedOp->getName() + ".trunc");
+      } else if (E.index() > 0 && isa<ConstantInt>(MappedOp) &&
+                 MappedOp->getType() != InferredTy) {
+        MappedOp = ConstantInt::get(InferredTy,
+                                    cast<ConstantInt>(MappedOp)->getZExtValue());
+      }
+      Ops.push_back(MappedOp);
+    }
+    assert(Ops.size() == 3 && "Select expects exactly 3 operands");
+    Cloned = SelectInst::Create(Ops[0], Ops[1], Ops[2], Instr->getName() + ".cloned");
+  } else {
+    Cloned = Instr->clone();
+  }
+
   if (!IsVoidRetTy) {
-    Cloned->setName(Instr->getName() + ".cloned");
+    if (!RebuildSelect)
+      Cloned->setName(Instr->getName() + ".cloned");
 #if !defined(NDEBUG)
     // Verify that VPlan type inference results agree with the type of the
     // generated values.
@@ -2850,16 +2893,19 @@ static void scalarizeInstruction(const Instruction *Instr,
   if (auto DL = RepRecipe->getDebugLoc())
     State.setDebugLocFrom(DL);

-  // Replace the operands of the cloned instructions with their scalar
-  // equivalents in the new loop.
-  for (const auto &I : enumerate(RepRecipe->operands())) {
-    auto InputLane = Lane;
-    VPValue *Operand = I.value();
-    if (vputils::isSingleScalar(Operand))
-      InputLane = VPLane::getFirstLane();
-    Cloned->setOperand(I.index(), State.get(Operand, InputLane));
+  // Replace the operands of the cloned instruction with their scalar
+  // equivalents if we cloned the original (non-rebuilt) instruction.
+  if (!RebuildSelect) {
+    for (const auto &I : enumerate(RepRecipe->operands())) {
+      auto InputLane = Lane;
+      VPValue *Operand = I.value();
+      if (vputils::isSingleScalar(Operand))
+        InputLane = VPLane::getFirstLane();
+      Cloned->setOperand(I.index(), State.get(Operand, InputLane));
+    }
   }

+
   // Place the cloned scalar in the new loop.
   State.Builder.Insert(Cloned);

